export enum Sender {
  User = 'user',
  Bot = 'bot'
}

export interface Message {
  id: string;
  text: string;
  sender: Sender;
  timestamp: number;
  image?: string; // Base64 string
  isThinking?: boolean;
}

export interface GenerationOptions {
  useThinking: boolean;
  useLite: boolean;
  image?: string;
}

export enum AppMode {
  Chat = 'chat',
  Settings = 'settings'
}

import React from 'react';

// Models
export const MODEL_THINKING = 'gemini-3-pro-preview';
export const MODEL_LITE = 'gemini-flash-lite-latest';
export const MODEL_TTS = 'gemini-2.5-flash-preview-tts';
export const MODEL_IMAGE_ANALYSIS = 'gemini-3-pro-preview'; // As per prompt requirement for image understanding

// Limits
export const MAX_THINKING_BUDGET = 32768;

export const PLACEHOLDER_IMAGE = 'https://picsum.photos/400/300';

import { GoogleGenAI, Modality } from "@google/genai";
import { MODEL_THINKING, MODEL_LITE, MODEL_TTS, MODEL_IMAGE_ANALYSIS, MAX_THINKING_BUDGET } from '../constants';
import { GenerationOptions } from '../types';

// Initialize the API client
// Note: In a real app, you might want to handle the missing key more gracefully in the UI.
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

/**
 * Generates text response based on user input and options.
 */
export const generateResponse = async (
  prompt: string,
  options: GenerationOptions
): Promise<string> => {
  try {
    const isImageAnalysis = !!options.image;

    // Determine the model to use
    let modelName = MODEL_LITE; // Default to Fast/Lite
    let config: any = {};

    if (options.useThinking && !isImageAnalysis) {
      // Thinking mode (text-only mostly, though 3-pro supports multimodal, thinking is best for complex text)
      modelName = MODEL_THINKING;
      config.thinkingConfig = { thinkingBudget: MAX_THINKING_BUDGET };
    } else if (isImageAnalysis) {
      // Image analysis requirement
      modelName = MODEL_IMAGE_ANALYSIS;
    } else if (options.useLite) {
      // Explicit Lite mode (redundant if default, but good for clarity)
      modelName = MODEL_LITE;
    } else {
      // Fallback or standard Pro use if we had a generic switch (here we simplify to Lite vs Thinking/Image)
      modelName = MODEL_LITE;
    }

    const parts: any[] = [];

    // Add Image if present
    if (options.image) {
      // Extract base64 data (remove "data:image/xyz;base64," prefix if present)
      const base64Data = options.image.split(',')[1];
      const mimeType = options.image.split(';')[0].split(':')[1];

      parts.push({
        inlineData: {
          mimeType: mimeType,
          data: base64Data
        }
      });
    }

    // Add Text Prompt
    parts.push({ text: prompt });

    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: config
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return `Error: ${error instanceof Error ? error.message : "Something went wrong"}`;
  }
};

/**
 * Generates speech from text using the TTS model.
 * Returns an AudioBuffer.
 */
export const generateSpeech = async (text: string): Promise<AudioBuffer | null> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_TTS,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
      throw new Error("No audio data returned");
    }

    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Decode logic
    const binaryString = atob(base64Audio);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }

    const audioBuffer = await audioContext.decodeAudioData(bytes.buffer);
    return audioBuffer;

  } catch (error) {
    console.error("TTS Error:", error);
    return null;
  }
};

/**
 * Helper to play an AudioBuffer
 */
export const playAudioBuffer = (buffer: AudioBuffer) => {
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
  const source = audioContext.createBufferSource();
  source.buffer = buffer;
  source.connect(audioContext.destination);
  source.start();
};

import React, { useState } from 'react';
import { Message, Sender } from '../types';
import { generateSpeech, playAudioBuffer } from '../services/geminiService';
import { Loader2, Play, Volume2 } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
}

const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isUser = message.sender === Sender.User;
  const [isPlaying, setIsPlaying] = useState(false);
  const [isGeneratingAudio, setIsGeneratingAudio] = useState(false);

  const handlePlayTTS = async () => {
    if (isPlaying || isGeneratingAudio) return;

    setIsGeneratingAudio(true);
    try {
      const buffer = await generateSpeech(message.text);
      if (buffer) {
        setIsPlaying(true);
        playAudioBuffer(buffer);
        // Reset playing state after duration (approximate)
        setTimeout(() => setIsPlaying(false), buffer.duration * 1000);
      }
    } catch (e) {
      console.error("Failed to play audio", e);
    } finally {
      setIsGeneratingAudio(false);
    }
  };

  return (
    <div className={`flex w-full mb-4 ${isUser ? 'justify-end' : 'justify-start'}`}>
      <div
        className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
          isUser
            ? 'bg-blue-600 text-white rounded-br-none'
            : 'bg-slate-800 text-slate-100 rounded-bl-none border border-slate-700'
        }`}
      >
        {/* Render Image if available */}
        {message.image && (
          <div className="mb-3 rounded-lg overflow-hidden border border-white/10">
            <img src={message.image} alt="User upload" className="w-full h-auto object-cover max-h-60" />
          </div>
        )}

        {/* Message Text */}
        <div className="whitespace-pre-wrap text-sm leading-relaxed">
           {message.text}
        </div>

        {/* Thinking Indicator Badge */}
        {message.isThinking && (
          <div className="mt-2 text-xs text-slate-400 flex items-center gap-1">
            <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-pulse"></span>
            Thinking Mode
          </div>
        )}

        {/* TTS Button (Bot only) */}
        {!isUser && (
          <div className="mt-3 flex items-center justify-end">
            <button
              onClick={handlePlayTTS}
              disabled={isGeneratingAudio || isPlaying}
              className="flex items-center gap-1.5 px-2 py-1 bg-slate-700/50 hover:bg-slate-700 rounded-md text-xs text-slate-300 transition-all active:scale-95"
            >
              {isGeneratingAudio ? (
                <Loader2 className="w-3 h-3 animate-spin" />
              ) : isPlaying ? (
                <Volume2 className="w-3 h-3 text-green-400" />
              ) : (
                <Play className="w-3 h-3" />
              )}
              {isGeneratingAudio ? "Loading..." : isPlaying ? "Playing" : "Listen"}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default MessageBubble;

import React from 'react';
import { BrainCircuit, Zap } from 'lucide-react';

interface SettingsPanelProps {
  useThinking: boolean;
  setUseThinking: (val: boolean) => void;
  useLite: boolean;
  setUseLite: (val: boolean) => void;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({ useThinking, setUseThinking, useLite, setUseLite }) => {
  return (
    <div className="p-4 bg-slate-900 border-t border-slate-800">
      <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
        {/* Thinking Mode Toggle */}
        <button
          onClick={() => {
            setUseThinking(!useThinking);
            if (!useThinking) setUseLite(false); // Mutually exclusive ideal
          }}
          className={`flex items-center gap-2 px-4 py-2 rounded-full border text-sm font-medium transition-all whitespace-nowrap ${
            useThinking
              ? 'bg-purple-900/40 border-purple-500 text-purple-200 shadow-[0_0_15px_rgba(168,85,247,0.3)]'
              : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'
          }`}
        >
          <BrainCircuit className="w-4 h-4" />
          Thinking Mode {useThinking && "(Max)"}
        </button>

        {/* Fast Mode Toggle */}
        <button
          onClick={() => {
            setUseLite(!useLite);
            if (!useLite) setUseThinking(false);
          }}
          className={`flex items-center gap-2 px-4 py-2 rounded-full border text-sm font-medium transition-all whitespace-nowrap ${
            useLite
              ? 'bg-yellow-900/40 border-yellow-500 text-yellow-200 shadow-[0_0_15px_rgba(234,179,8,0.2)]'
              : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'
          }`}
        >
          <Zap className="w-4 h-4" />
          Fast Responses
        </button>
      </div>
    </div>
  );
};

export default SettingsPanel;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Image as ImageIcon, X, Loader2, Sparkles, Menu } from 'lucide-react';
import { Message, Sender } from './types';
import { generateResponse } from './services/geminiService';
import MessageBubble from './components/MessageBubble';
import SettingsPanel from './components/SettingsPanel';
import ShareButton from './components/ShareButton';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      text: "Hello! I'm your Gemini AI assistant. I can see, speak, and think deeply. How can I help you today?",
      sender: Sender.Bot,
      timestamp: Date.now()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  // Settings State
  const [useThinking, setUseThinking] = useState(false);
  const [useLite, setUseLite] = useState(true); // Default to Lite for speed

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = async () => {
    if ((!inputText.trim() && !selectedImage) || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      text: inputText,
      sender: Sender.User,
      timestamp: Date.now(),
      image: selectedImage || undefined
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      const responseText = await generateResponse(userMessage.text || (userMessage.image ? "Describe this image" : ""), {
        useThinking,
        useLite,
        image: userMessage.image
      });

      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: Sender.Bot,
        timestamp: Date.now(),
        isThinking: useThinking && !userMessage.image // Only tag as thinking if we actually used thinking mode (not valid for images usually unless supported)
      };

      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      console.error(error);
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        text: "Sorry, something went wrong. Please check your connection and try again.",
        sender: Sender.Bot,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-950 text-slate-100 font-sans">
      {/* Header */}
      <header className="flex-none p-4 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 flex items-center justify-between sticky top-0 z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <h1 className="font-bold text-lg tracking-tight">Gemini Mobile</h1>
        </div>
        <ShareButton />
      </header>

      {/* Messages Area */}
      <main className="flex-1 overflow-y-auto p-4 scroll-smooth">
        <div className="max-w-3xl mx-auto flex flex-col gap-2">
          {messages.map((msg) => (
            <MessageBubble key={msg.id} message={msg} />
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-slate-800 rounded-2xl rounded-bl-none p-4 border border-slate-700 flex items-center gap-3">
                <Loader2 className="w-5 h-5 text-blue-400 animate-spin" />
                <span className="text-slate-400 text-sm">
                  {useThinking ? "Thinking deeply..." : "Generating..."}
                </span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
      </main>

      {/* Controls & Input */}
      <footer className="flex-none bg-slate-950/90 backdrop-blur-sm sticky bottom-0 z-20">

        {/* Settings Toggle Area */}
        <SettingsPanel 
          useThinking={useThinking} 
          setUseThinking={setUseThinking}
          useLite={useLite}
          setUseLite={setUseLite}
        />

        {/* Selected Image Preview */}
        {selectedImage && (
          <div className="px-4 py-2 flex items-center gap-2">
            <div className="relative inline-block">
              <img src={selectedImage} alt="Selected" className="h-16 w-16 object-cover rounded-lg border border-slate-700" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute -top-2 -right-2 bg-red-500 rounded-full p-0.5 text-white shadow-md hover:bg-red-600"
              >
                <X className="w-3 h-3" />
              </button>
            </div>
            <span className="text-xs text-slate-400">Image attached</span>
          </div>
        )}

        {/* Input Area */}
        <div className="p-4 pt-2 max-w-3xl mx-auto">
          <div className="flex gap-2 items-end bg-slate-900 border border-slate-800 rounded-2xl p-2 focus-within:ring-2 focus-within:ring-blue-500/50 focus-within:border-blue-500 transition-all shadow-lg">

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="p-3 text-slate-400 hover:text-blue-400 hover:bg-slate-800 rounded-xl transition-colors"
              title="Upload Image"
            >
              <ImageIcon className="w-6 h-6" />
            </button>
            <input 
              type="file" 
              accept="image/*" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleImageSelect}
            />

            <textarea
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={useThinking ? "Ask a complex question..." : "Message Gemini..."}
              className="flex-1 bg-transparent border-none text-slate-100 placeholder-slate-500 focus:ring-0 resize-none max-h-32 py-3 text-base"
              rows={1}
              style={{ minHeight: '44px' }}
            />

            <button
              onClick={handleSendMessage}
              disabled={(!inputText.trim() && !selectedImage) || isLoading}
              className={`p-3 rounded-xl transition-all ${
                (!inputText.trim() && !selectedImage) || isLoading
                  ? 'bg-slate-800 text-slate-600 cursor-not-allowed'
                  : 'bg-blue-600 text-white hover:bg-blue-500 shadow-md hover:shadow-blue-500/20 active:scale-95'
              }`}
            >
              <Send className="w-5 h-5" />
            </button>
          </div>
          <div className="text-center mt-2">
            <p className="text-[10px] text-slate-600">
               Using {useThinking ? 'Gemini 3 Pro (Thinking)' : 'Gemini 2.5'} • AI can make mistakes.
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

