import React, { useState, useRef, useEffect } from 'react';
import { Send, Image as ImageIcon, X, Loader2, Sparkles } from 'lucide-react';
import { Message, Sender } from './types';
import { generateResponse } from './services/geminiService';
import MessageBubble from './components/MessageBubble';
import SettingsPanel from './components/SettingsPanel';
import ShareButton from './components/ShareButton';
import InstallButton from './components/InstallButton';

const STORAGE_KEY = 'achille_chat_history';

const INITIAL_MESSAGE: Message = {
  id: '1',
  text: "Hello! I'm ACHILLE, your AI assistant. I can see, speak, and think deeply. How can I help you today?",
  sender: Sender.Bot,
  timestamp: Date.now()
};

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [INITIAL_MESSAGE];
  });
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  // Settings State
  const [useThinking, setUseThinking] = useState(false);
  const [useLite, setUseLite] = useState(true);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = (behavior: ScrollBehavior = 'smooth') => {
    messagesEndRef.current?.scrollIntoView({ behavior });
  };

  // Save messages to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
    scrollToBottom();
  }, [messages]);

  const handleClearHistory = () => {
    if (window.confirm("Are you sure you want to clear your entire chat history?")) {
      setMessages([INITIAL_MESSAGE]);
      localStorage.removeItem(STORAGE_KEY);
